tinymce.PluginManager.add('customer_label', function(editor, url) {
  var openDialog = function () {
    editor.insertContent(` <span class='unselectable' unselectable="on"  contenteditable=false onmousedown="return false"  style="margin: 0 3px 3px;
    margin: 0 3px 3px;
    padding: 4px 6px;
    color: rgb(24, 144, 255);
    background-color: rgba(24, 144, 255,0.15);
    user-select: none;
    font-size: 13px;
    border-radius: 2px;user-select:none;">客户昵称</span>`);

  };

  // 注册一个工具栏按钮名称
  editor.ui.registry.addButton('customer_label', {
    text: '客户昵称',
    onAction: function () {
      openDialog();
    }
  });

  // 注册一个菜单项名称 menu/menubar
  editor.ui.registry.addMenuItem('customer_label', {
    text: 'customer_label菜单名',
    onAction: function() {
      openDialog();
    }
  });

  return {
    getMetadata: function () {
      return  {
        //插件名和链接会显示在“帮助”→“插件”→“已安装的插件”中
        name: "customer_label plugin",//插件名称
        url: "http://customer_labelplugindocsurl.com", //作者网址
      };
    }
  };
});
